-- Ken's Hardened V2 Fix

local b64_0xlIIl1l = {}
local char_0xl1lIII='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xIIIl1I=1,#char_0xl1lIII do b64_0xlIIl1l[char_0xl1lIII:sub(i_0xIIIl1I,i_0xIIIl1I)] = i_0xIIIl1I - 1 end

function b64_0xlIIl1l.dec_0x11lIIl(d_0xlII111)
    d_0xlII111 = string.gsub(d_0xlII111, '[^'..char_0xl1lIII..'=]', '')
    local r_0xlIlllI = {}
    for i_0xIIIl1I=1, #d_0xlII111, 4 do
        local c_0xlIIII1 = b64_0xlIIl1l[d_0xlII111:sub(i_0xIIIl1I,i_0xIIIl1I)] or 0
        local c_0xIllIlI = b64_0xlIIl1l[d_0xlII111:sub(i_0xIIIl1I+1,i_0xIIIl1I+1)] or 0
        local c_0xlIIIII, c_0xlII1II = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xlII111:sub(i_0xIIIl1I+2,i_0xIIIl1I+2)
        if ch3 == "=" then has3 = false else c_0xlIIIII = b64_0xlIIl1l[ch3] or 0 end
        local ch4 = d_0xlII111:sub(i_0xIIIl1I+3,i_0xIIIl1I+3)
        if ch4 == "=" then has4 = false else c_0xlII1II = b64_0xlIIl1l[ch4] or 0 end
        local b_0x1IlIll = c_0xlIIII1 * (2^18) + c_0xIllIlI * (2^12) + c_0xlIIIII * (2^6) + c_0xlII1II
        local b_0x1I1111 = math.floor(b_0x1IlIll / (2^16)) % (2^8)
        local b_0xllIIII = math.floor(b_0x1IlIll / (2^8)) % (2^8)
        local b_0xlIIIl1 = b_0x1IlIll % (2^8)
        table.insert(r_0xlIlllI, string.char(b_0x1I1111))
        if has3 then table.insert(r_0xlIlllI, string.char(b_0xllIIII)) end
        if has4 then table.insert(r_0xlIlllI, string.char(b_0xlIIIl1)) end
    end
    return table.concat(r_0xlIlllI)
end


local function bxor_0xlIIlIl(a_0xll1Ill,b_0xlllII1)
    if bit32 then return bit32.bxor(a_0xll1Ill,b_0xlllII1) end
    local r_0xllII1I = 0
    for i_0xIlIIlI = 0, 7 do
        local x_0x1lIlII = a_0xll1Ill % 2
        local y_0xIIIl1l = b_0xlllII1 % 2
        if x_0x1lIlII ~= y_0xIIIl1l then r_0xllII1I = r_0xllII1I + (2^i_0xIlIIlI) end
        a_0xll1Ill = math.floor(a_0xll1Ill / 2)
        b_0xlllII1 = math.floor(b_0xlllII1 / 2)
    end
    return r_0xllII1I
end


local function bxor_str_0xllIIIl(s_0x1lI1lI, k_0xllIllI)
    local r_0xlIl1I1 = {}
    for i_0x11lIlI=1, #s_0x1lI1lI do
        local b_0x11IllI = string.byte(s_0x1lI1lI, i_0x11lIlI)
        local kb_0xlIIIll = string.byte(k_0xllIllI, (i_0x11lIlI-1) % #k_0xllIllI + 1)
        r_0xlIl1I1[i_0x11lIlI] = string.char(bxor_0xlIIlIl(b_0x11IllI, kb_0xlIIIll))
    end
    return table.concat(r_0xlIl1I1)
end


local function getkeys_0xlIllII()
    local seed = b64_0xlIIl1l.dec_0x11lIIl("OWFZY3pzN3Q=")
    local k1_enc = b64_0xlIIl1l.dec_0x11lIIl("XhMgFgkjbQY=")
    local k2_enc = b64_0xlIIl1l.dec_0x11lIIl("dRUgDB8FRhc=")
    return bxor_str_0xllIIIl(k1_enc, seed), bxor_str_0xllIIIl(k2_enc, seed)
end


local function cff_0xIIII1I(a_0xlI1llI)
    local st_0xIllll1 = 0
    local res_0xllIllI = a_0xlI1llI
    while true do
        if st_0xIllll1 == 0 then
            res_0xllIllI = res_0xllIllI + 1
            st_0xIllll1 = 1
        elseif st_0xIllll1 == 1 then
            res_0xllIllI = res_0xllIllI * 2
            st_0xIllll1 = 2
        elseif st_0xIllll1 == 2 then
            res_0xllIllI = res_0xllIllI - 3
            st_0xIllll1 = 3
        else
            break
        end
    end
    return res_0xllIllI
end


local function chain_0x1l1lIl(x) return x*2 end
local function chain_0xlI1ll1(x) return chain_0x1l1lIl(x)+1 end


local d_0x1Il1lI = {
  {op=255, val="", is_enc=true},
}
local pc_0xlIIIlI = 1
local stk_0xI11IIl = {}
stk_0xI11IIl._jmp = nil


local disp_0xIIIlII = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xlIllII()

local state_0xIIlI1l = 0
while true do
    if state_0xIIlI1l == 0 then  -- FETCH
        if pc_0xlIIIlI > #d_0x1Il1lI then break end
        local inst = d_0x1Il1lI[pc_0xlIIIlI]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xlIIl1l.dec_0x11lIIl(val)
            d = bxor_str_0xllIIIl(d, k2)
            val = bxor_str_0xllIIIl(d, k1)
        end
        stk_0xI11IIl._jmp = nil
        pc_0xlIIIlI = pc_0xlIIIlI + 1
        cur_op_0xIl11II = opcode
        cur_val_0xIl1I1l = val
        state_0xIIlI1l = 1

    elseif state_0xIIlI1l == 1 then  -- EXECUTE
        local handler = disp_0xIIIlII[cur_op_0xIl11II]
        if handler then
            handler(stk_0xI11IIl, cur_val_0xIl1I1l)
        end
        if stk_0xI11IIl._jmp then
            pc_0xlIIIlI = pc_0xlIIIlI + stk_0xI11IIl._jmp
        end
        state_0xIIlI1l = 0
